The alphametics puzzle solver has been implemented and verified. All tests are passing. The solution utilizes backtracking to find the correct digit assignment for each unique letter, ensuring that leading letters are not assigned zero and each letter represents a unique digit.

The solution in `alphametics.js` is:

```javascript
export const solve = (puzzle) => {
  // Parse the puzzle
  const parts = puzzle.split(' == ');
  const leftSide = parts[0];
  const rightSide = parts[1];

  const leftWords = leftSide.split(' + ').map(w => w.trim());
  const rightWords = [rightSide.trim()];

  // Find all unique letters
  const allLetters = new Set();
  for (const word of [...leftWords, ...rightWords]) {
    for (const ch of word) {
      allLetters.add(ch);
    }
  }
  const letters = [...allLetters];

  if (letters.length > 10) return null;

  // Find leading letters (cannot be zero for multi-digit words)
  const leadingLetters = new Set();
  for (const word of [...leftWords, ...rightWords]) {
    if (word.length > 1) {
      leadingLetters.add(word[0]);
    }
  }

  // Calculate coefficients for each letter
  // Equation: sum(leftWords) = sum(rightWords)
  // Rewritten: sum(leftWords) - sum(rightWords) = 0
  const coefficients = {};
  for (const letter of letters) {
    coefficients[letter] = 0;
  }

  for (const word of leftWords) {
    for (let i = 0; i < word.length; i++) {
      const power = word.length - 1 - i;
      coefficients[word[i]] += Math.pow(10, power);
    }
  }

  for (const word of rightWords) {
    for (let i = 0; i < word.length; i++) {
      const power = word.length - 1 - i;
      coefficients[word[i]] -= Math.pow(10, power);
    }
  }

  // Backtracking solver
  const used = new Array(10).fill(false);
  const assignment = {};

  function solveBacktrack(idx) {
    if (idx === letters.length) {
      // Check if equation is satisfied
      let sum = 0;
      for (const letter of letters) {
        sum += coefficients[letter] * assignment[letter];
      }
      return sum === 0;
    }

    const letter = letters[idx];
    const canBeZero = !leadingLetters.has(letter);

    for (let digit = canBeZero ? 0 : 1; digit <= 9; digit++) {
      if (!used[digit]) {
        used[digit] = true;
        assignment[letter] = digit;

        if (solveBacktrack(idx + 1)) {
          return true;
        }

        used[digit] = false;
        delete assignment[letter];
      }
    }

    return false;
  }

  if (solveBacktrack(0)) {
    return assignment;
  }

  return null;
};
```
